/**
 * @method
 * @name setParamset
 * @description 파라미터 추가
 * @param {string} selectId 팝업 SELECT ID
 * @param {array} param1 desc
 * @param {string} param2 desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setParamset = function(pSelectID, options, param1, param2) {
    switch(pSelectID) {
        case "retrieveRentloanList":
            param1[11] = "계약번호";
            param2[2] = options.pYear;
            if(options.pWtitleSearch != null) {
                let strArr = options.pWtitleSearch.split(",");
                if(strArr != null) {
                    param1[0] = strArr[0];          //타이틀
                    param1[1] = strArr[1];          //조회조건명 1
                    param1[2] = strArr[2];          //조회조건명 2
                    if(strArr[11] != null) {
                        param1[11] = strArr[11];    //조회조건명 3
                    }
                }
            }
            break;
        case "retrieveAcctDeptCdInfo10":
            param1[11] = "회계연도";
            param2[2] = options.pYear;
            if(options.pWtitleSearch != null) {
                let strArr = options.pWtitleSearch.split(",");
                if(strArr != null) {
                    param1[0] = strArr[0];          //타이틀
                    param1[1] = strArr[1];          //조회조건명 1
                    param1[2] = strArr[2];          //조회조건명 2
                    if(strArr[11] != null) {
                        param1[11] = strArr[11];    //조회조건명 3
                    }
                }
            }
            break;
        case "retrieveAccdVehclInfo":
            if(options.pWhere=="TR") {
                param1[0] = "차량코드조회";     //타이틀
                param1[1] = "단축코드";         //조회조건명 1
                param1[2] = "차량번호";         //조회조건명 2
            }
            else if (options.pWhere == "LO") {
                param1[0] = "차량코드조회";     //타이틀
                param1[1] = "장비번호";         //조회조건명 1
                param1[2] = "차량번호";         //조회조건명 2
            }
            break;
        default:
    }
};

/**
 * @method
 * @name getPopupUrl
 * @description url 정보
 * @param {string} selectId 팝업 SELECT ID
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.getPopupUrl = function(pSelectID) {
    let url;
    let parentMenuId; 
    let parentPgmId;
    if($p.parent().$p.getAllParameter() != null){
        if($p.parent().$p.getAllParameter().paramData.menuInfo.parentMenuId !== undefined){
            parentMenuId = $p.parent().$p.getAllParameter().paramData.menuInfo.parentMenuId;
            parentPgmId = $p.parent().$p.getAllParameter().paramData.menuInfo.pgmId;
        }
        else{
            parentMenuId = $p.parent().$p.getAllParameter().paramData.menuInfo.menuId;
            parentPgmId = $p.parent().$p.getAllParameter().paramData.menuInfo.pgmId;
        }
    }
    else{
        parentMenuId = $p.parent().$p.parent().$p.getAllParameter().paramData.menuInfo.menuId;
        parentPgmId = $p.parent().$p.parent().$p.getAllParameter().paramData.menuInfo.pgmId;
    }
    if (parentMenuId && parentMenuId.indexOf("n") !== -1) {
        // if(parentPgmId == "zz_620_01_01b.jsp" || parentPgmId == "zz_670_01_01b.jsp" ){
        //     return "/cm/xml/commonPopup.xml";
        // }
        // else{
            return "/cm/xml/commonPopupNcall.xml";
        // }
    }
// console.log("scwin.getPopupUrl > pSelectID : " + pSelectID);    
    switch(pSelectID) {
        case "retrieveRentloanList":
            url = "/ui/ac/fm/collmoneymgnt/rcptmgnt/fm_502_03_04p.xml";
            break;
        case "retrieveAcctDeptCdInfo10":
            url = "/cm/xml/commonPopup2.xml";
            break;
        case "retrieveCarNrmCdInfo":
            url = "/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_17p.xml";
            break;
        case "retrieveContainerNo":
            url = "/cm/zz/commonContainerPopup.xml";
            break;
        case "retrieveConteinerInfo":
            url = "/ui/ds/op/wrkrslts/railroadwrkrslts/op_205_01_01p.xml";
            break;
        case "retrieveTchPcVehclList":
        case "retrieveTchPcLotNo":
        case "retrieveTmlAdmitckCdInfo":
        case "retrieveTchPcVehclShortNoPopup":
        case "retrieveTchPcSizePopup":
            url = "/cm/zz/commonToPopup.xml";
            break;
        case "retrieveBlNo":
        case "retrieveBookingNo":
        case "retrieveOdrNo":
            url = "/ui/ds/op/wrkrslts/cywrkrslts/op_301_02_03p1.xml";
            break;
        case "retrieveOrderVolume":
            url = "/ui/ds/op/wrkplan/railroadwrkplan/op_203_01_01p.xml";
            break;
        case "retrieveRentCarVehclNewInfo":
            url = "/ui/ps/rc/op/accdmgnt/rc_330_01_n02p.xml";
            break;
        case "retrieveVatDeclarAcctDeptCd":
        case "retrieveVatDeclarAcctDeptCdAcctDeptCd":
            url = "/ui/ac/fi/stdinfomgnt/fi_100_06_01p.xml";
            break;
        case "retrieveIFRSAcctCdInfo":
            url = "/ui/ac/fi/ifrs/stdinfomgnt/fi_500_01_01p.xml";
            break;
        case "retrieveIFRSAcctCdInfo2":
            url = "/ui/ac/fi/ifrs/stdinfomgnt/fi_500_02_01p.xml";
            break;
        case "retrieveDongbuGroupCompanyInfo":
            url = "/ui/ac/fi/stdinfomgnt/fi_100_02_02p.xml";
            break;
        // Ncall(Ntis) 대상(t_popupdefine.js)
        case "retrieveZipList_tpro":
