/**
 * @method
 * @name setGridLogic
 * @description 팝업 그리드 세팅 로직
 * @param {string} selectId 팝업 SELECT ID
 * @param {object} options desc
 * @param {array} arrParm desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setGridLogic = function (selectId, options, arrParm) {
    let sTitle;
    let sHidden;
// console.log("scwin.setGridLogic selectId : "+selectId);    
	switch(selectId) {
        //타이틀,조회조건Title1,조회조건Title2,XML_SELECT_ID,PopupClose유무(T/F),Display칼럼개수,중복체크여부,전체검색여부,입력Len(CD),입력Len(NM),POPUP조건입력Disable여부
        case "retrieveZipList":
            arrParm[0] = ["우편번호","우편번호","동이름", options.pSelectID,options.pWinCloseTF,options.iDispCnt,options.pExistTF,options.pAllSearchTF,null,null,null];
            sTitle = "우편번호,주소,주소,COL4,COL5,COL6,COL7,COL8,COL9,Info";
            sHidden = "2,4,5,6,7,8,9,10";
            break;
        case "retrieveFmsZipList":
